app.ws("/ws", {
  open(socket, ctx) {
    const userId = ctx.state.userContext?.id;
    if (!userId) { socket.close(1008, "Unauthorized"); return; }
    hub.subscribe(`user:${userId}`, socket);
  },
  message(socket, event) {
    socket.send(`echo: ${event.data}`);
  },
  close(socket, code, reason) {
    hub.unsubscribe(socket);
  },
  error(socket, event) {
    console.error("ws error", event);
  },
}, { idleTimeout: 30 });

app.use(authMiddleware);  // sets ctx.state.userContext

app.ws("/ws", {
  open(socket, ctx) {
    if (!ctx.state.userContext) socket.close(1008, "Unauthorized");
  },
});

app.ws("/realtime", handlers, { port: 8443, idleTimeout: 60 });

// app.listen() starts the main HTTP listener AND the WS listener on 8443
app.listen({ port: 8000 });
